class Solution:
    def nextBeautifulNumber(self, n: int) -> int:
        def is_beautiful(num):
            count = [0] * 10
            for digit in str(num):
                count[int(digit)] += 1
            for i in range(10):
                if count[i] != i and i != 0:
                    return False
            return True

        num = n + 1
        while not is_beautiful(num):
            num += 1
        return num
